import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function UsrProfile() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch((err) => console.log(err));
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">
        <div className="backdrop-blur-lg bg-white/30 p-6 rounded-xl shadow-lg text-gray-700">
          Loading profile...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200 p-6 flex justify-center">

      <div className="w-full max-w-md">

        {/* MAIN CARD */}
        <div className="backdrop-blur-xl bg-white/30 border border-white/40 shadow-2xl rounded-2xl p-8">

          {/* PROFILE HEADER */}
          <div className="text-center">

            <div className="relative inline-block">
              <img
                src={
                  user.profileImage ||
                  `https://ui-avatars.com/api/?name=${user.username}`
                }
                className="w-28 h-28 rounded-full object-cover border-4 border-white shadow-lg"
                alt="profile"
              />

              <div className="absolute inset-0 rounded-full blur-xl bg-indigo-400 opacity-30"></div>
            </div>

            <h2 className="text-2xl font-bold mt-4 text-gray-800">
              {user.name}
            </h2>

            <p className="text-gray-600">{user.email}</p>

            <span className="inline-block mt-2 px-3 py-1 text-xs rounded-full bg-indigo-500 text-white shadow">
              {user.role}
            </span>
          </div>

          {/* DIVIDER */}
          <div className="border-t border-white/40 my-6"></div>

          {/* STACKED INFO (UNDER PROFILE PHOTO STYLE) */}
          <div className="space-y-3">

            <div className="bg-white/20 backdrop-blur p-3 rounded-xl flex justify-between">
              <span className="font-semibold text-gray-700">Username</span>
              <span className="text-gray-800">{user.username}</span>
            </div>

            <div className="bg-white/20 backdrop-blur p-3 rounded-xl flex justify-between">
              <span className="font-semibold text-gray-700">Full Name</span>
              <span className="text-gray-800">{user.name}</span>
            </div>

            <div className="bg-white/20 backdrop-blur p-3 rounded-xl flex justify-between">
              <span className="font-semibold text-gray-700">Email</span>
              <span className="text-gray-800 text-right break-all">
                {user.email}
              </span>
            </div>

            <div className="bg-white/20 backdrop-blur p-3 rounded-xl flex justify-between">
              <span className="font-semibold text-gray-700">Role</span>
              <span className="text-gray-800">{user.role}</span>
            </div>

          </div>

          {/* BUTTON */}
          <button
            onClick={() => navigate("/edit-usr-profile")}
            className="w-full mt-6 bg-gradient-to-r from-indigo-500 to-purple-600 text-white py-2 rounded-lg shadow-md hover:scale-105 transition"
          >
            Edit Profile
          </button>

        </div>
      </div>
    </div>
  );
}
